/*RwdMapper.uptImageFileUpList*/
UPDATE MSP_RWD_FILE_OUT
   SET PROC_YN = #{procYn}
       , PROC_DT = TO_CHAR(SYSDATE, 'YYYYMMDD')
 WHERE RWD_FILE_OUT_SEQ = #{rwdFileOutSeq}

/*RwdMapper.uptRwdOutUpList*/
UPDATE MSP_RWD_INFO_OUT
   SET PROC_YN = #{procYn}
       , PROC_DT = TO_CHAR(SYSDATE, 'YYYYMMDD')
 WHERE RWD_SEQ = #{rwdSeq}

/*RwdMapper.updateBuyPric*/
UPDATE MSP_RWD_INFO_OUT
   SET BUY_PRIC = trim(#{buyPric})
 WHERE RWD_SEQ = #{rwdSeq}

/*RwdMapper.updateRwdAddSvc*/
UPDATE MSP_RWD_MEMBER
   SET RSLT_CD = #{rsltCd}
       , RSLT_MSG = #{rsltMsg}
       , RVISN_ID = 'BATCH_ADD'
       , RVISN_DTTM = SYSDATE
 WHERE CONTRACT_NUM = #{contractNum}
   AND RWD_STAT_CD = '0'
   AND STRT_DTTM IS NULL
   AND CAN_RSLT_CD IS NULL

/*RwdMapper.updateRwdSvc*/
UPDATE MSP_RWD_INFO_OUT
   SET STRT_DTTM = SUBSTR(#{effectiveDate}, 1,8)
       , END_DTTM = SUBSTR(#{expirationDate}, 1,8)

       , CAN_DTTM = SUBSTR(#{canDttm}, 1,8)

       , INFO_OUT_TYPE = #{infoOutType}
       , RWD_STAT_CD = #{rwdStatCd}
       , RSLT_DT = TO_CHAR(SYSDATE, 'YYYYMMDD')
 WHERE RWD_SEQ = #{rwdSeq}

/*RwdMapper.updateMemberStat*/
UPDATE MSP_RWD_MEMBER
   SET STRT_DTTM = #{effectiveDate}
       , END_DTTM = #{expirationDate}
       , RWD_STAT_CD = #{rwdStatCd}
       , RVISN_ID = 'BATCH_SUC'
       , RVISN_DTTM = SYSDATE
 WHERE RWD_SEQ = #{rwdSeq}

