/*RwdMapper.insertRwdCmpnRes*/
INSERT INTO MSP_RWD_CMPN_IN (
	RWD_CMPN_IN_SEQ
	, RWD_SEQ
	, RWD_CMPN_SEQ
	, CMPN_CT
	, CMPN_DT
	, CMPN_ID
	, CMPN_STAT_CD
	, REGST_DTTM
	, PROC_DT
	, PROC_YN
) VALUES (
	RWD_CMPN_IN_SEQ.NEXTVAL
	, #{rwdSeq}
	, #{rwdCmpnSeq}
	, #{cmpnCt}
	, #{cmpnDt}
	, #{cmpnId}
	, #{cmpnStatCd}
	, SYSDATE
	, TO_CHAR(SYSDATE, 'YYYYMMDD')
	, 'N'
)

